def gen(rng, size):
    import string
    n = max(1, size)
    logs = []
    for i in range(n):
        ident = rng.choice(string.ascii_lowercase) + str(rng.randint(1, 99))
        if rng.random() < 0.5:
            words = [rng.choice(string.ascii_lowercase) * rng.randint(1, 4) for _ in range(rng.randint(1, 3))]
            logs.append(ident + ' ' + ' '.join(words))
        else:
            nums = [str(rng.randint(0, 9)) for _ in range(rng.randint(1, 4))]
            logs.append(ident + ' ' + ' '.join(nums))
    return [logs]

