class Solution:
    def reorderLogFiles(self, logs):
        def is_digit_log(log):
            parts = log.split()
            return parts[1].isdigit()
        letter_logs = [l for l in logs if not is_digit_log(l)]
        digit_logs = [l for l in logs if is_digit_log(l)]
        letter_logs.sort(key=lambda l: (l.split(' ', 1)[1], l.split(' ', 1)[0]))
        return letter_logs + digit_logs

