var reorderLogFiles = function(logs) {
    const isDigit = log => /^\d/.test(log.split(' ')[1]);
    const letters = [], digits = [];
    for (const log of logs) {
        (isDigit(log) ? digits : letters).push(log);
    }
    letters.sort((a, b) => {
        const [ai, ...arest] = a.split(' ');
        const [bi, ...brest] = b.split(' ');
        const ac = arest.join(' '), bc = brest.join(' ');
        if (ac !== bc) return ac < bc ? -1 : 1;
        return ai < bi ? -1 : ai > bi ? 1 : 0;
    });
    return [...letters, ...digits];
};
